select * from position

    company_id = #{companyId}

        and position_name like concat('%', #{positionName}, '%')


        and department = #{department}


        and status = #{status}


order by create_time desc

mapper.update:
UPDATE position p
SET 
    p.recruited_count = (
        SELECT COUNT(*) 
        FROM student_internship_status sis 
        WHERE sis.position_id = #{positionId} 
        AND sis.status IN (1, 2)
    ),
    p.remaining_quota = p.planned_recruit - (
        SELECT COUNT(*) 
        FROM student_internship_status sis 
        WHERE sis.position_id = #{positionId} 
        AND sis.status IN (1, 2)
    ),
    p.update_time = NOW()
WHERE p.id = #{positionId}
